external_knowledge:
; A business unit is considered to have outstanding invoices if it has at least one invoice with 'isOpen' = 1, indicating that the invoice is still open; 
; The 'total invoiced amount' refers to the sum of all invoice amounts for a business unit; 
; The 'total payment made' refers to the sum of all payments recorded for the invoices of a business unit, defaulting to 0 if there are no payment records; 
; The 'unpaid balance' is the difference between the total invoiced amount and the total payment made.

sql:
SELECT business_name
FROM business_units
WHERE business_code = '1';
